#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <omp.h>

#define RADIUS 7
#define BLOCK_SIZE 256

void stencil_1d(const int *in, int *out, int length) {
    int num_blocks = length / BLOCK_SIZE;

    #pragma omp parallel for schedule(static, 1)
    for (int block_idx = 0; block_idx < num_blocks; block_idx++) {
        int temp[BLOCK_SIZE + 2 * RADIUS];
        int gindex_base = block_idx * BLOCK_SIZE;

        // Load main block data into shared temp array (simulated as local array)
        // lindex = threadIdx.x + RADIUS
        for (int t = 0; t < BLOCK_SIZE; t++) {
            int gindex = gindex_base + t;
            int lindex = t + RADIUS;
            temp[lindex] = in[gindex];
        }

        // Handle boundary loads for threads where threadIdx.x < RADIUS
        // In the CUDA code, these specific threads load the left and right padding
        // We replicate this logic sequentially for the block
        for (int t = 0; t < RADIUS; t++) {
            int gindex = gindex_base + t;
            int lindex = t + RADIUS;

            // Left side: temp[lindex - RADIUS]
            int left_gindex = gindex - RADIUS;
            temp[lindex - RADIUS] = (left_gindex < 0) ? 0 : in[left_gindex];

            // Right side: temp[lindex + BLOCK_SIZE]
            int right_gindex = gindex + BLOCK_SIZE;
            // The original CUDA code accesses in[gindex + BLOCK_SIZE]. 
            // Since 'in' is allocated with pad_size = (length + RADIUS), 
            // and gindex + BLOCK_SIZE can be up to (num_blocks-1)*BLOCK_SIZE + BLOCK_SIZE = length.
            // If length < pad_size, this access is valid.
            temp[lindex + BLOCK_SIZE] = in[right_gindex];
        }

        // Compute stencil
        for (int t = 0; t < BLOCK_SIZE; t++) {
            int gindex = gindex_base + t;
            int lindex = t + RADIUS;
            int result = 0;
            for (int offset = -RADIUS; offset <= RADIUS; offset++) {
                result += temp[lindex + offset];
            }
            out[gindex] = result;
        }
    }
}

int main(int argc, char* argv[]) {
    if (3 != argc) {
        printf("Usage: %s <length> <repeat>\n", argv[0]);
        printf("length is a multiple of %d\n", BLOCK_SIZE);
        return 1;
    }
    const int length = atoi(argv[1]);
    const int repeat = atoi(argv[2]);

    int size = length * sizeof(int);
    int pad_size = (length + RADIUS) * sizeof(int);

    int *a, *b;

    a = (int *)malloc(pad_size); 
    b = (int *)malloc(size);

    for (int i = 0; i < length + RADIUS; i++) a[i] = i;

    // Initialize output buffer (though stencil writes all, good practice)
    // The CUDA code doesn't explicitly initialize d_b, but assumes overwrite.

    auto start = std::chrono::steady_clock::now();

    for (int i = 0; i < repeat; i++) {
        stencil_1d(a, b, length);
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

    // Verification logic exactly matching the original CUDA host code
    bool ok = true;

    // First check range: 0 to 2*RADIUS - 1
    for (int i = 0; i < 2*RADIUS; i++) {
        int s = 0;
        // Original loop: for (int j = i; i+2*RADIUS >= j; j++)
        // Condition: j <= i + 2*RADIUS
        // Inner term: (RADIUS > j ? 0 : (a[j] - RADIUS))
        // Note: The original CUDA verification code has a specific logic here.
        // It sums from j=i to j=i+2*RADIUS.
        // Term is 0 if j < RADIUS, else a[j-RADIUS].
        for (int j = i; j <= i + 2*RADIUS; j++) {
            s += (j < RADIUS) ? 0 : (a[j - RADIUS]);
        }
        if (b[i] != s) {
            printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
            ok = false;
            break;
        }
    }

    // Second check range: 2*RADIUS to length - 1
    for (int i = 2*RADIUS; i < length; i++) {
        int s = 0;
        // Original loop: for (int j = i-RADIUS; i+RADIUS >= j; j++)
        // Condition: j <= i + RADIUS
        // Term: a[j]
        for (int j = i - RADIUS; j <= i + RADIUS; j++) {
            s += a[j];
        }
        if (b[i] != s) {
            printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
            ok = false;
            break;
        }
    }

    printf("%s\n", ok ? "PASS" : "FAIL");

    free(a);
    free(b); 
    return 0;
}
